// src/utils/firebase.js
import { initializeApp } from "firebase/app";
import { getFirestore, collection, addDoc, getDocs, query, orderBy, limit } from "firebase/firestore";

const firebaseConfig = {
  apiKey: "AIzaSyBihVc93BZ5mubGZQVhmzsz-wkeVXkpreI",
  authDomain: "clario-28105.firebaseapp.com",
  projectId: "clario-28105",
  storageBucket: "clario-28105.firebasestorage.app",
  messagingSenderId: "495711462842",
  appId: "1:495711462842:web:201da00b5a38490e252983",
  measurementId: "G-CVGF9WL7JW",
};

const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);

export async function saveSession(sessionData) {
  try {
    await addDoc(collection(db, "sessions"), {
      ...sessionData,
      createdAt: new Date(),
    });
  } catch (e) {
    console.warn("Firebase save failed (check config):", e.message);
  }
}

export async function getSessions(limitCount = 20) {
  try {
    const q = query(collection(db, "sessions"), orderBy("createdAt", "desc"), limit(limitCount));
    const snap = await getDocs(q);
    return snap.docs.map((d) => ({ id: d.id, ...d.data() }));
  } catch (e) {
    console.warn("Firebase fetch failed:", e.message);
    return [];
  }
}
